import { useClerkSupabase } from '@/shared/hooks/useClerkSupabase';
import {
  createDevSupabaseClient,
  isDevelopmentEnvironment,
} from '@/shared/lib/supabase/client';
import type { Database } from '@/shared/lib/supabase/types';
import { setAuthenticatedClient } from '@/shared/utils/authenticatedClient';
import type { SupabaseClient } from '@supabase/supabase-js';
import type { ReactNode } from 'react';
import { createContext, useContext, useEffect } from 'react';

interface AuthenticatedSupabaseContextType {
  supabaseClient: SupabaseClient<Database> | null;
}

const AuthenticatedSupabaseContext =
  createContext<AuthenticatedSupabaseContextType | null>(null);

export function AuthenticatedSupabaseProvider({
  children,
}: {
  children: ReactNode;
}) {
  // Hooks must run unconditionally (Rules-of-Hooks).
  // Cloud-only: the dev/service-role path is dead, so always use the Clerk client.
  const clerkClient = useClerkSupabase();
  const isDevelopment = isDevelopmentEnvironment();
  const supabaseClient = isDevelopment
    ? createDevSupabaseClient()
    : clerkClient;

  // Set the authenticated client for stores to use
  useEffect(() => {
    if (supabaseClient) {
      setAuthenticatedClient(supabaseClient);
    }
  }, [supabaseClient]);

  return (
    <AuthenticatedSupabaseContext.Provider value={{ supabaseClient }}>
      {children}
    </AuthenticatedSupabaseContext.Provider>
  );
}

export function useAuthenticatedSupabase() {
  const context = useContext(AuthenticatedSupabaseContext);
  if (!context || !context.supabaseClient) {
    throw new Error(
      'useAuthenticatedSupabase must be used within AuthenticatedSupabaseProvider'
    );
  }
  return context.supabaseClient;
}

import { SignedIn, SignedOut, SignUp } from '@clerk/react-router';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { Navigate, Route, Routes } from 'react-router-dom';

// Components
import ClerkSupabaseProvider from './features/auth/components/ClerkSupabaseProvider';
import DevAuthProvider from './features/auth/components/DevAuthProvider';
import ProtectedRoute from './features/auth/components/ProtectedRoute';
import { ErrorBoundary } from './shared/components/common/error/ErrorBoundary';
import { AuthenticatedSupabaseProvider } from './shared/contexts/AuthenticatedSupabaseContext';
import { CanvasHeaderProvider } from './shared/contexts/CanvasHeaderContext';

// Pages
import AssetsPage from './features/assets/pages/AssetsPage';
import CanvasLayout from './features/canvas/components/CanvasLayout';
import CanvasPage from './features/canvas/pages/CanvasPage';
import CanvasSettingsPage from './features/canvas/pages/CanvasSettingsPage';
import EnhancedCanvasPage from './features/canvas/pages/EnhancedCanvasPage';

import DashboardPage from './features/dashboard/pages/DashboardPage';
import EvidencePage from './features/evidence/pages/EvidencePage';
import EvidenceRepositoryPage from './features/evidence/pages/EvidenceRepositoryPage';
import HomePage from './features/projects/pages/HomePage';
import SourcePage from './features/sources/pages/SourcePage';

// Auth Pages
import SignInPage from './features/auth/pages/SignInPage';

// Create a client
const queryClient = new QueryClient();

// Check if we're in development mode (using local Supabase)
import { isDevelopmentEnvironment } from '@/shared/lib/supabase/client';
const isDevelopment = isDevelopmentEnvironment();

export default function App() {
  console.log('App component rendering');
  console.log('VITE_SUPABASE_URL:', import.meta.env.VITE_SUPABASE_URL);
  console.log('isDevelopment:', isDevelopment);

  return (
    <ErrorBoundary>
      <QueryClientProvider client={queryClient}>
        {isDevelopment ? (
          // Development mode - use DevAuthProvider
          <DevAuthProvider>
            <AuthenticatedSupabaseProvider>
              <Routes>
                {/* Development routes - no auth required */}
                <Route path="/" element={<HomePage />} />
                <Route
                  path="/debug"
                  element={
                    <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
                      <div className="text-center">
                        <h1 className="text-2xl font-bold mb-4">Debug Page</h1>
                        <p className="mb-4">Development mode is active!</p>
                        <div className="space-y-2 text-sm text-gray-600">
                          <p>✅ App component rendered</p>
                          <p>✅ Development auth provider loaded</p>
                          <p>✅ Local Supabase connected</p>
                          <p>✅ No Clerk authentication required</p>
                        </div>
                      </div>
                    </div>
                  }
                />
                <Route path="/evidence" element={<EvidenceRepositoryPage />} />
                <Route
                  path="/evidence/:evidenceId"
                  element={<EvidencePage />}
                />

                <Route
                  path="/canvas/:canvasId"
                  element={
                    <CanvasHeaderProvider>
                      <CanvasLayout />
                    </CanvasHeaderProvider>
                  }
                >
                  <Route index element={<CanvasPage />} />
                  <Route path="enhanced" element={<EnhancedCanvasPage />} />
                  <Route path="dashboard" element={<DashboardPage />} />
                  <Route path="assets" element={<AssetsPage />} />
                  <Route path="evidence" element={<EvidenceRepositoryPage />} />
                  <Route
                    path="evidence/:evidenceId"
                    element={<EvidencePage />}
                  />
                  <Route path="source" element={<SourcePage />} />
                  <Route path="settings" element={<CanvasSettingsPage />} />
                </Route>
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </AuthenticatedSupabaseProvider>
          </DevAuthProvider>
        ) : (
          // Production mode - use Clerk authentication
          <ClerkSupabaseProvider>
            <AuthenticatedSupabaseProvider>
              <Routes>
                {/* Auth routes with Clerk */}
                <Route
                  path="/auth/sign-in"
                  element={
                    <>
                      <SignedOut>
                        <SignInPage />
                      </SignedOut>
                      <SignedIn>
                        <Navigate to="/" replace />
                      </SignedIn>
                    </>
                  }
                />
                <Route
                  path="/auth/sign-up"
                  element={
                    <>
                      <SignedOut>
                        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-green-50 to-emerald-100 p-4">
                          <SignUp />
                        </div>
                      </SignedOut>
                      <SignedIn>
                        <Navigate to="/" replace />
                      </SignedIn>
                    </>
                  }
                />

                {/* Protected routes */}
                <Route
                  path="/"
                  element={
                    <ProtectedRoute>
                      <HomePage />
                    </ProtectedRoute>
                  }
                />

                {/* Debug route - always accessible */}
                <Route
                  path="/debug"
                  element={
                    <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
                      <div className="text-center">
                        <h1 className="text-2xl font-bold mb-4">Debug Page</h1>
                        <p className="mb-4">
                          If you can see this, the app is working!
                        </p>
                        <div className="space-y-2 text-sm text-gray-600">
                          <p>✅ App component rendered</p>
                          <p>✅ Clerk provider loaded</p>
                          <p>✅ Routing is working</p>
                        </div>
                      </div>
                    </div>
                  }
                />

                {/* Evidence Repository */}
                <Route
                  path="/evidence"
                  element={
                    <ProtectedRoute>
                      <EvidenceRepositoryPage />
                    </ProtectedRoute>
                  }
                />
                <Route
                  path="/evidence/:evidenceId"
                  element={
                    <ProtectedRoute>
                      <EvidencePage />
                    </ProtectedRoute>
                  }
                />

                {/* Canvas routes - With sidebar layout */}
                <Route
                  path="/canvas/:canvasId"
                  element={
                    <ProtectedRoute>
                      <CanvasHeaderProvider>
                        <CanvasLayout />
                      </CanvasHeaderProvider>
                    </ProtectedRoute>
                  }
                >
                  <Route index element={<CanvasPage />} />
                  <Route path="enhanced" element={<EnhancedCanvasPage />} />
                  <Route path="dashboard" element={<DashboardPage />} />
                  <Route path="assets" element={<AssetsPage />} />
                  <Route path="evidence" element={<EvidenceRepositoryPage />} />
                  <Route
                    path="evidence/:evidenceId"
                    element={<EvidencePage />}
                  />
                  <Route path="source" element={<SourcePage />} />
                  <Route path="settings" element={<CanvasSettingsPage />} />

                  {/* Development-only routes */}
                  {/* TODO: Re-add XStateCanvasDemo when component is recreated */}
                </Route>

                {/* Catch-all route for unauthenticated users */}
                <Route
                  path="*"
                  element={
                    <SignedOut>
                      <Navigate to="/auth/sign-in" replace />
                    </SignedOut>
                  }
                />
              </Routes>
            </AuthenticatedSupabaseProvider>
          </ClerkSupabaseProvider>
        )}
      </QueryClientProvider>
    </ErrorBoundary>
  );
}

import { isDevelopmentEnvironment } from '@/shared/lib/supabase/client';
import { ClerkProvider } from '@clerk/react-router';
import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import App from './App.tsx';
import DevUserbackInitializer from './shared/components/common/feedback/DevUserbackInitializer';
import UserbackInitializer from './shared/components/common/feedback/UserbackInitializer';
import './styles/index.css';

// Import your Publishable Key
const PUBLISHABLE_KEY = import.meta.env.VITE_CLERK_PUBLISHABLE_KEY;

console.log('Clerk Publishable Key:', PUBLISHABLE_KEY ? 'Set' : 'Not set');

if (!PUBLISHABLE_KEY) {
  console.error(
    'Missing Clerk Publishable Key. Please add VITE_CLERK_PUBLISHABLE_KEY to your .env file'
  );
  // Instead of throwing, let's show a helpful error page
  createRoot(document.getElementById('root')!).render(
    <StrictMode>
      <div
        style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          height: '100vh',
          fontFamily: 'system-ui, sans-serif',
          padding: '20px',
          textAlign: 'center',
        }}
      >
        <div>
          <h1>🚨 Configuration Error</h1>
          <p>Missing Clerk Publishable Key</p>
          <p>
            Please add <code>VITE_CLERK_PUBLISHABLE_KEY</code> to your .env file
          </p>
          <p>
            Get your key from the{' '}
            <a
              href="https://dashboard.clerk.com"
              target="_blank"
              rel="noopener"
            >
              Clerk Dashboard
            </a>
          </p>
        </div>
      </div>
    </StrictMode>
  );
  throw new Error('Add your Clerk Publishable Key to the .env file');
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <BrowserRouter>
      <ClerkProvider publishableKey={PUBLISHABLE_KEY}>
        {isDevelopmentEnvironment() ? (
          <DevUserbackInitializer />
        ) : (
          <UserbackInitializer />
        )}
        <Routes>
          <Route path="/*" element={<App />} />
        </Routes>
      </ClerkProvider>
    </BrowserRouter>
  </StrictMode>
);

