export type RelationshipType =
  | 'Deterministic'
  | 'Probabilistic'
  | 'Causal'
  | 'Compositional';

export type ConfidenceLevel = 'High' | 'Medium' | 'Low';

export type CausalFactor =
  | 'Component Drift'
  | 'Temporal Variance'
  | 'Influence Drift'
  | 'Dimension Drift'
  | 'Event Shocks';

export type SourceType = 'Manual' | 'Calculated' | 'Random';

export type Dimension =
  | 'Qualitative'
  | 'Quantitative'
  | 'Vanity'
  | 'Actionable'
  | 'Efficiency'
  | 'Effectiveness'
  | 'Strategic'
  | 'Tactical'
  | 'Operational';

// Data structures
export interface MetricValue {
  period: string;
  value: number;
  change_percent: number;
  trend: 'up' | 'down' | 'neutral';
}

export interface MetricCard {
  id: string;
  title: string;
  description: string;
  category: CardCategory;
  subCategory?: CardSubCategory[CardCategory];
  tags: string[];
  causalFactors: CausalFactor[];
  dimensions: Dimension[];
  segments?: Segment[];

  // Position on canvas
  position: { x: number; y: number };

  // React Flow subflow support
  parentId?: string; // ID of the group this node belongs to

  // Data for Data/Metric cards
  data?: MetricValue[];
  sourceType?: SourceType;
  formula?: string;

  // Metadata
  owner?: string;
  assignees: string[];
  createdAt: string;
  updatedAt: string;
}

export interface Segment {
  id: string;
  name: string;
  dimension: string;
  value: string;
  percentage?: number;
  filters?: SegmentFilter[];
  color?: string;
  isActive: boolean;
  description?: string;
  createdAt: string;
}

export interface SegmentFilter {
  field: string;
  operator: 'equals' | 'contains' | 'greater_than' | 'less_than' | 'between';
  value: string | number | [number, number];
}

export interface Relationship {
  id: string;
  sourceId: string;
  targetId: string;
  type: RelationshipType;
  confidence: ConfidenceLevel;
  weight?: number;

  // Evidence and knowledge
  evidence: EvidenceItem[];
  notes?: string;

  // History for influence drift analysis
  history?: RelationshipHistoryEntry[];

  // Metadata
  createdAt: string;
  updatedAt: string;
}

export interface RelationshipHistoryEntry {
  id: string;
  timestamp: string;
  changeType: 'strength' | 'confidence' | 'type' | 'evidence';
  oldValue: any;
  newValue: any;
  description: string;
  userId?: string;
  annotation?: string; // User can add context for the change
}

export interface EvidenceItem {
  id: string;
  title: string;
  type:
    | 'Experiment'
    | 'Analysis'
    | 'Notebook'
    | 'External Research'
    | 'User Interview';
  date: string;
  owner: string;
  link?: string;
  hypothesis?: string;
  summary: string;
  impactOnConfidence?: string;
  createdAt?: string;
  createdBy?: string;
  updatedAt?: string;
  tags?: string[];
  category?: string;

